INSERT INTO beliefs VALUES('fdc56aa2-f580-49a4-88e0-e1ae2cd6bb77','fang-poll false positive bug FIXED on 2026-03-19. Root cause: 1) fmt.mjs only included ID column when hasMedia=true, so text-only chats had no ID column. 2) fang-poll parsed formatted table output, grabbing Content as the watermark ID. 3) tr -d [:space:] in watermark read stripped spaces within IDs. Fix: rewrote fang-poll to use raw JSON API via python3 instead of parsing formatted table output. Also fixed fmt.mjs to always include ID column.','infrastructure',0.949999999999999955,'[]',0,0,1773895493885,1773895493885,NULL,NULL,NULL,5,'["fang-poll","watermark","fix-applied"]','[0.048412095602377844,0.09156660229360616,0.0037222196054311455,0.0033913556405039324,0.0009909805443030972,0.00042989015161317454,0.018073626487845135,0.19896917229020514,0.0022646063204996587,0.04877970347233116,0,0.0919265339063955,0.033846423741912185,0.003164992125991287,0,0.01280763157619091,0.0007630550191133848,0.0035459149552280094,0.0021494507580658725,0,0.004260786584622377,0,0.0011139489330122404,0,0.011698323407718333,0,0.014628652784713175,0.00043478918467999134,0.16898200241456415,0.0025163041326396155,0.008986745277264003,0,0.026166567890745493,0.004901592767567759,0.006522889513004564,0.0020794067462979846,0.0008011076316151021,0,0,0.09418039993064888,0.005407293778996918,0.0021914093836962302,0.0009003599045585661,0.012480666570690227,0,0.1454969327170653,0,0.00044623100532946474,0.009184921526364817,0.003928520698762331,0.0021567146469564182,0.0036502684320053103,0.09419782649744543,0.003133251523989722,0.007435872915028711,0.0038308177930566527,0.0003582417930109788,0.041589215437633414,0.002519705084391432,0,0.021039685434642325,0,0.0070155880869141795,0.001919635268209773,0.026279711345575742,0.0010747253790329362,0.0007426326220081604,0.09156660229360616,0.10136482095958141,0.00042510028919965726,0.003405584674388459,0.002643882023355961,0.0007499312227158573,0,0.02365505736540409,0,0.0021958417816212513,0